parameters.jsCode:
const raw = $input.item.json;
const src = raw.body || raw;
const rule = src.rule || {};
const agent = src.agent || {};
const data = src.data || {};

return {
  json: {
    level: rule.level,
    description: rule.description,
    ruleId: rule.id,
    groups: rule.groups || [],
    agentName: agent.name,
    agentIp: agent.ip,
    srcIp: data.srcip,
    fullLog: src.full_log,
    timestamp: src.timestamp
  }
};

const alert = $('Normalize Alert').item.json;
const input = $input.item.json;
const abuseData = input.data && typeof input.data.abuseConfidenceScore !== 'undefined' ? input.data : null;

const abuseLine = abuseData
  ? `AbuseIPDB: confidence=${abuseData.abuseConfidenceScore}%, country=${abuseData.countryCode || 'n/a'}, isp=${abuseData.isp || 'n/a'}, totalReports=${abuseData.totalReports}`
  : 'AbuseIPDB: no data (no source IP, lookup skipped, or lookup failed)';

const aiPrompt = `Analyze this Wazuh security alert. Reply with a 2-3 sentence triage summary and a priority of Low/Medium/High/Critical.\n\nAlert: ${alert.description}\nRule ID: ${alert.ruleId}  Level: ${alert.level}\nAgent: ${alert.agentName} (${alert.agentIp})\nSource IP: ${alert.srcIp}\nGroups: ${alert.groups}\nRaw log: ${alert.fullLog}\n${abuseLine}`;

return {
  json: {
    ...alert,
    abuseConfidenceScore: abuseData ? abuseData.abuseConfidenceScore : null,
    abuseCountry: abuseData ? abuseData.countryCode : null,
    abuseTotalReports: abuseData ? abuseData.totalReports : null,
    aiPrompt
  }
};

const alert = $('Build AI Prompt').item.json;
const aiResp = $input.item.json;

const groups = alert.groups || [];
const groupsStr = Array.isArray(groups) ? groups.join(' ') : String(groups);

let suggestion = "No predefined suggestion — review manually.";
if (groupsStr.includes('authentication_fail')) {
  suggestion = "Repeated auth failures. Check if the source IP/user is expected, look for a brute-force pattern, consider a temporary block if external and repeated.";
} else if (groupsStr.includes('web')) {
  suggestion = "Web-layer alert. Check for a known CVE match, review the request payload for injection patterns, check WAF/reverse-proxy logs.";
} else if (groupsStr.includes('malware') || groupsStr.includes('rootkit')) {
  suggestion = "Possible malware/rootkit indicator. Consider isolating the host from the network and capturing volatile data before any remediation — do not auto-remediate.";
} else if (groupsStr.includes('firewall') || groupsStr.includes('ids')) {
  suggestion = "Network-layer alert. Correlate source/destination with your asset inventory and check for a scanning pattern.";
}
if (alert.abuseConfidenceScore !== null && alert.abuseConfidenceScore !== undefined && alert.abuseConfidenceScore >= 50) {
  suggestion += ` Source IP has a ${alert.abuseConfidenceScore}% AbuseIPDB confidence score (${alert.abuseTotalReports} reports) — treat as higher priority.`;
}

const aiSummary = typeof aiResp.response === 'string' && aiResp.response.trim()
  ? aiResp.response.trim()
  : "(AI Analysis node not enabled yet — see sticky note)";

return {
  json: {
    level: alert.level,
    description: alert.description,
    ruleId: alert.ruleId,
    groups: alert.groups,
    agentName: alert.agentName,
    agentIp: alert.agentIp,
    srcIp: alert.srcIp,
    fullLog: alert.fullLog,
    timestamp: alert.timestamp,
    abuseConfidenceScore: alert.abuseConfidenceScore,
    abuseCountry: alert.abuseCountry,
    abuseTotalReports: alert.abuseTotalReports,
    aiSummary,
    suggestedResponse: suggestion,
    note: "Suggested response is a rule-based hint only — no automated action has been taken."
  }
};

parameters.jsonBody:
={
  "embeds": [
    {
      "title": {{ JSON.stringify($json.description || 'Wazuh Alert') }},
      "color": {{ $json.level >= 12 ? 15158332 : ($json.level >= 9 ? 15105570 : 3447003) }},
      "fields": [
        { "name": "Level", "value": {{ JSON.stringify(String($json.level)) }}, "inline": true },
        { "name": "Agent", "value": {{ JSON.stringify(($json.agentName || 'n/a') + ' (' + ($json.agentIp || 'n/a') + ')') }}, "inline": true },
        { "name": "Source IP", "value": {{ JSON.stringify($json.srcIp || 'n/a') }}, "inline": true },
        { "name": "IP Reputation (AbuseIPDB)", "value": {{ JSON.stringify(($json.abuseConfidenceScore !== null && $json.abuseConfidenceScore !== undefined) ? ($json.abuseConfidenceScore + '% confidence, ' + ($json.abuseTotalReports || 0) + ' reports, ' + ($json.abuseCountry || 'n/a')) : 'no data') }}, "inline": true },
        { "name": "AI Summary", "value": {{ JSON.stringify($json.aiSummary || 'n/a') }} },
        { "name": "Suggested Next Step", "value": {{ JSON.stringify($json.suggestedResponse || 'n/a') }} }
      ]
    }
  ]
}
